// Başlanğıc siyahı
let breakfastList = ["yumurta", "süd", "çörək", "pendir"];

// 1. push: Siyahının sonuna element əlavə edir
breakfastList.push("qatıq");
console.log(breakfastList); // ["yumurta", "süd", "çörək", "pendir", "qatıq"]

// 2. pop: Siyahının son elementini silir və qaytarır
let removed = breakfastList.pop();
console.log(breakfastList); // ["yumurta", "süd", "çörək", "pendir"]
console.log(removed); // "qatıq"

// 3. shift: Siyahının ilk elementini silir və qaytarır
removed = breakfastList.shift();
console.log(breakfastList); // ["süd", "çörək", "pendir"]
console.log(removed); // "yumurta"

// 4. unshift: Siyahının əvvəlinə element əlavə edir
breakfastList.unshift("kərə yağı");
console.log(breakfastList); // ["kərə yağı", "süd", "çörək", "pendir"]

// 5. concat: İki və ya daha çox siyahını birləşdirir
let moreItems = ["bal", "cem"];
let newList = breakfastList.concat(moreItems);
console.log(newList); // ["kərə yağı", "süd", "çörək", "pendir", "bal", "cem"]

// 6. slice: Siyahının bir hissəsini qaytarır (orijinal dəyişmir)
let sliced = breakfastList.slice(1, 3);
console.log(sliced); // ["süd", "çörək"]

// 7. splice: Elementləri silir və ya əlavə edir
breakfastList.splice(1, 1, "şorba");
console.log(breakfastList); // ["kərə yağı", "şorba", "çörək", "pendir"]

// 8. forEach: Hər element üçün funksiya işlədir
breakfastList.forEach(item => console.log("Al: " + item));
// nəticə: Al: kərə yağı, Al: şorba, Al: çörək, Al: pendir

// 9. map: Hər elementi çevirir və yeni siyahı qaytarır
let upperList = breakfastList.map(item => item.toUpperCase());
console.log(upperList); // ["KƏRƏ YAĞI", "ŞORBA", "ÇÖRƏK", "PENDİR"]

// 10. filter: Şərtə uyğun elementləri qaytarır
let shortItems = breakfastList.filter(item => item.length < 5);
console.log(shortItems); // ["şorba"]

// 11. find: Şərtə uyğun ilk elementi qaytarır
let found = breakfastList.find(item => item.startsWith("p"));
console.log(found); // "pendir"

// 12. findIndex: Şərtə uyğun ilk elementin indeksini qaytarır
let index = breakfastList.findIndex(item => item.startsWith("p"));
console.log(index); // 3

// 13. includes: Siyahıda elementin olub-olmadığını yoxlayır
console.log(breakfastList.includes("çörək")); // true

// 14. indexOf: Elementin ilk indeksini qaytarır
console.log(breakfastList.indexOf("çörək")); // 2

// 15. lastIndexOf: Elementin son indeksini qaytarır
breakfastList.push("çörək");
console.log(breakfastList.lastIndexOf("çörək")); // 4

// 16. join: Elementləri birləşdirib mətn qaytarır
let joined = breakfastList.join(", ");
console.log(joined); // "kərə yağı, şorba, çörək, pendir, çörək"

// 17. reverse: Siyahını tərsinə çevirir
breakfastList.reverse();
console.log(breakfastList); // ["çörək", "pendir", "çörək", "şorba", "kərə yağı"]

// 18. sort: Siyahını sıralayır
breakfastList.sort();
console.log(breakfastList); // ["çörək", "çörək", "kərə yağı", "pendir", "şorba"]

// 19. every: Bütün elementlərin şərtə uyğunluğunu yoxlayır
let allShort = breakfastList.every(item => item.length < 10);
console.log(allShort); // true

// 20. some: Ən azı bir elementin şərtə uyğunluğunu yoxlayır
let hasLong = breakfastList.some(item => item.length > 5);
console.log(hasLong); // true

// 21. reduce: Siyahını tək dəyərə çevirir
let totalLength = breakfastList.reduce((sum, item) => sum + item.length, 0);
console.log(totalLength); // 27

// 22. reduceRight: Siyahını tək dəyərə sağdan sola çevirir
let rightTotal = breakfastList.reduceRight((sum, item) => sum + item.length, 0);
console.log(rightTotal); // 27

// 23. flat: Daxili siyahıları açır
let nestedList = ["yumurta", ["süd", "çörək"], "pendir"];
let flatList = nestedList.flat();
console.log(flatList); // ["yumurta", "süd", "çörək", "pendir"]

// 24. flatMap: Hər elementi çevirir və düzləşdirir
let mappedFlat = breakfastList.flatMap(item => [item, item]);
console.log(mappedFlat); // ["çörək", "çörək", "çörək", "çörək", ...]

// 25. fill: Siyahını müəyyən dəyərlə doldurur
let filled = new Array(3).fill("tost");
console.log(filled); // ["tost", "tost", "tost"]

// 26. copyWithin: Siyahının bir hissəsini kopyalayır
breakfastList.copyWithin(0, 2, 3);
console.log(breakfastList); // ["çörək", "çörək", "çörək", "pendir", "şorba"]

// 27. toString: Siyahını mətnə çevirir
console.log(breakfastList.toString()); // "çörək,çörək,çörək,pendir,şorba"

// 28. at: Müəyyən indeksdəki elementi qaytarır
console.log(breakfastList.at(1)); // "çörək"

// 29. entries: Elementlərin indeks və dəyər cütlərini qaytarır
let iterator = breakfastList.entries();
console.log([...iterator]); // [[0, "çörək"], [1, "çörək"], ...]

// 30. keys: Siyahının indekslərini qaytarır
let keys = breakfastList.keys();
console.log([...keys]); // [0, 1, 2, 3, 4]

// 31. values: Siyahının dəyərlərini qaytarır
let values = breakfastList.values();
console.log([...values]); // ["çörək", "çörək", "çörək", "pendir", "şorba"]

// 32. Array.from: Digər strukturlardan array yaradır
let text = "süd";
let fromText = Array.from(text);
console.log(fromText); // ["s", "ü", "d"]

// 33. Array.isArray: Dəyərin array olub-olmadığını yoxlayır
console.log(Array.isArray(breakfastList)); // true

