// Starting list
let breakfastList = ["eggs", "milk", "bread", "cheese"];

// 1. push: Adds elements to the end
breakfastList.push("yogurt");
console.log(breakfastList); // ["eggs", "milk", "bread", "cheese", "yogurt"]

// 2. pop: Removes and returns the last element
let removed = breakfastList.pop();
console.log(breakfastList); // ["eggs", "milk", "bread", "cheese"]
console.log(removed); // "yogurt"

// 3. shift: Removes and returns the first element
removed = breakfastList.shift();
console.log(breakfastList); // ["milk", "bread", "cheese"]
console.log(removed); // "eggs"

// 4. unshift: Adds elements to the start
breakfastList.unshift("butter");
console.log(breakfastList); // ["butter", "milk", "bread", "cheese"]

// 5. concat: Merges two or more arrays
let moreItems = ["honey", "jam"];
let newList = breakfastList.concat(moreItems);
console.log(newList); // ["butter", "milk", "bread", "cheese", "honey", "jam"]

// 6. slice: Returns a portion of the array (original unchanged)
let sliced = breakfastList.slice(1, 3);
console.log(sliced); // ["milk", "bread"]

// 7. splice: Removes or adds elements
breakfastList.splice(1, 1, "soup");
console.log(breakfastList); // ["butter", "soup", "bread", "cheese"]

// 8. forEach: Runs a function for each element
breakfastList.forEach(item => console.log("Buy: " + item));
// Output: Buy: butter, Buy: soup, Buy: bread, Buy: cheese

// 9. map: Transforms elements and returns a new array
let upperList = breakfastList.map(item => item.toUpperCase());
console.log(upperList); // ["BUTTER", "SOUP", "BREAD", "CHEESE"]

// 10. filter: Returns elements matching a condition
let shortItems = breakfastList.filter(item => item.length < 5);
console.log(shortItems); // ["soup"]

// 11. find: Returns the first element matching a condition
let found = breakfastList.find(item => item.startsWith("c"));
console.log(found); // "cheese"

// 12. findIndex: Returns the index of the first matching element
let index = breakfastList.findIndex(item => item.startsWith("c"));
console.log(index); // 3

// 13. includes: Checks if an element exists
console.log(breakfastList.includes("bread")); // true

// 14. indexOf: Returns the first index of an element
console.log(breakfastList.indexOf("bread")); // 2

// 15. lastIndexOf: Returns the last index of an element
breakfastList.push("bread");
console.log(breakfastList.lastIndexOf("bread")); // 4

// 16. join: Joins elements into a string
let joined = breakfastList.join(", ");
console.log(joined); // "butter, soup, bread, cheese, bread"

// 17. reverse: Reverses the array
breakfastList.reverse();
console.log(breakfastList); // ["bread", "cheese", "bread", "soup", "butter"]

// 18. sort: Sorts the array
breakfastList.sort();
console.log(breakfastList); // ["bread", "bread", "butter", "cheese", "soup"]

// 19. every: Checks if all elements meet a condition
let allShort = breakfastList.every(item => item.length < 10);
console.log(allShort); // true

// 20. some: Checks if any element meets a condition
let hasLong = breakfastList.some(item => item.length > 5);
console.log(hasLong); // true

// 21. reduce: Reduces the array to a single value
let totalLength = breakfastList.reduce((sum, item) => sum + item.length, 0);
console.log(totalLength); // 27

// 22. reduceRight: Reduces from right to left
let rightTotal = breakfastList.reduceRight((sum, item) => sum + item.length, 0);
console.log(rightTotal); // 27

// 23. flat: Flattens nested arrays
let nestedList = ["eggs", ["milk", "bread"], "cheese"];
let flatList = nestedList.flat();
console.log(flatList); // ["eggs", "milk", "bread", "cheese"]

// 24. flatMap: Maps and flattens
let mappedFlat = breakfastList.flatMap(item => [item, item]);
console.log(mappedFlat); // ["bread", "bread", "bread", "bread", ...]

// 25. fill: Fills the array with a value
let filled = new Array(3).fill("toast");
console.log(filled); // ["toast", "toast", "toast"]

// 26. copyWithin: Copies part of the array within itself
breakfastList.copyWithin(0, 2, 3);
console.log(breakfastList); // ["bread", "bread", "bread", "cheese", "soup"]

// 27. toString: Converts array to string
console.log(breakfastList.toString()); // "bread,bread,bread,cheese,soup"

// 28. at: Returns element at specified index
console.log(breakfastList.at(1)); // "bread"

// 29. entries: Returns index-value pairs
let iterator = breakfastList.entries();
console.log([...iterator]); // [[0, "bread"], [1, "bread"], ...]

// 30. keys: Returns array indices
let keys = breakfastList.keys();
console.log([...keys]); // [0, 1, 2, 3, 4]

// 31. values: Returns array values
let values = breakfastList.values();
console.log([...values]); // ["bread", "bread", "bread", "cheese", "soup"]

// 32. Array.from: Creates array from other structures
let text = "milk";
let fromText = Array.from(text);
console.log(fromText); // ["m", "i", "l", "k"]

// 33. Array.isArray: Checks if a value is an array
console.log(Array.isArray(breakfastList)); // true

