// Начальный список
let breakfastList = ["яйца", "молоко", "хлеб", "сыр"];

// 1. push: Добавляет элементы в конец
breakfastList.push("йогурт");
console.log(breakfastList); // ["яйца", "молоко", "хлеб", "сыр", "йогурт"]

// 2. pop: Удаляет и возвращает последний элемент
let removed = breakfastList.pop();
console.log(breakfastList); // ["яйца", "молоко", "хлеб", "сыр"]
console.log(removed); // "йогурт"

// 3. shift: Удаляет и возвращает первый элемент
removed = breakfastList.shift();
console.log(breakfastList); // ["молоко", "хлеб", "сыр"]
console.log(removed); // "яйца"

// 4. unshift: Добавляет элементы в начало
breakfastList.unshift("масло");
console.log(breakfastList); // ["масло", "молоко", "хлеб", "сыр"]

// 5. concat: Объединяет два или более массивов
let moreItems = ["мёд", "джем"];
let newList = breakfastList.concat(moreItems);
console.log(newList); // ["масло", "молоко", "хлеб", "сыр", "мёд", "джем"]

// 6. slice: Возвращает часть массива (оригинал не меняется)
let sliced = breakfastList.slice(1, 3);
console.log(sliced); // ["молоко", "хлеб"]

// 7. splice: Удаляет или добавляет элементы
breakfastList.splice(1, 1, "суп");
console.log(breakfastList); // ["масло", "суп", "хлеб", "сыр"]

// 8. forEach: Выполняет функцию для каждого элемента
breakfastList.forEach(item => console.log("Купи: " + item));
// Вывод: Купи: масло, Купи: суп, Купи: хлеб, Купи: сыр

// 9. map: Преобразует элементы и возвращает новый массив
let upperList = breakfastList.map(item => item.toUpperCase());
console.log(upperList); // ["МАСЛО", "СУП", "ХЛЕБ", "СЫР"]

// 10. filter: Возвращает элементы, соответствующие условию
let shortItems = breakfastList.filter(item => item.length < 5);
console.log(shortItems); // ["суп"]

// 11. find: Возвращает первый элемент, соответствующий условию
let found = breakfastList.find(item => item.startsWith("с"));
console.log(found); // "сыр"

// 12. findIndex: Возвращает индекс первого подходящего элемента
let index = breakfastList.findIndex(item => item.startsWith("с"));
console.log(index); // 3

// 13. includes: Проверяет наличие элемента
console.log(breakfastList.includes("хлеб")); // true

// 14. indexOf: Возвращает первый индекс элемента
console.log(breakfastList.indexOf("хлеб")); // 2

// 15. lastIndexOf: Возвращает последний индекс элемента
breakfastList.push("хлеб");
console.log(breakfastList.lastIndexOf("хлеб")); // 4

// 16. join: Объединяет элементы в строку
let joined = breakfastList.join(", ");
console.log(joined); // "масло, суп, хлеб, сыр, хлеб"

// 17. reverse: Переворачивает массив
breakfastList.reverse();
console.log(breakfastList); // ["хлеб", "сыр", "хлеб", "суп", "масло"]

// 18. sort: Сортирует массив
breakfastList.sort();
console.log(breakfastList); // ["масло", "суп", "сыр", "хлеб", "хлеб"]

// 19. every: Проверяет, все ли элементы соответствуют условию
let allShort = breakfastList.every(item => item.length < 10);
console.log(allShort); // true

// 20. some: Проверяет, соответствует ли хотя бы один элемент
let hasLong = breakfastList.some(item => item.length > 5);
console.log(hasLong); // true

// 21. reduce: Сводит массив к одному значению
let totalLength = breakfastList.reduce((sum, item) => sum + item.length, 0);
console.log(totalLength); // 27

// 22. reduceRight: Сводит массив справа налево
let rightTotal = breakfastList.reduceRight((sum, item) => sum + item.length, 0);
console.log(rightTotal); // 27

// 23. flat: Разворачивает вложенные массивы
let nestedList = ["яйца", ["молоко", "хлеб"], "сыр"];
let flatList = nestedList.flat();
console.log(flatList); // ["яйца", "молоко", "хлеб", "сыр"]

// 24. flatMap: Преобразует и разворачивает
let mappedFlat = breakfastList.flatMap(item => [item, item]);
console.log(mappedFlat); // ["масло", "масло", "суп", "суп", ...]

// 25. fill: Заполняет массив значением
let filled = new Array(3).fill("тост");
console.log(filled); // ["тост", "тост", "тост"]

// 26. copyWithin: Копирует часть массива внутри него
breakfastList.copyWithin(0, 2, 3);
console.log(breakfastList); // ["хлеб", "хлеб", "хлеб", "сыр", "суп"]

// 27. toString: Преобразует массив в строку
console.log(breakfastList.toString()); // "хлеб,хлеб,хлеб,сыр,суп"

// 28. at: Возвращает элемент по индексу
console.log(breakfastList.at(1)); // "хлеб"

// 29. entries: Возвращает пары индекс-значение
let iterator = breakfastList.entries();
console.log([...iterator]); // [[0, "хлеб"], [1, "хлеб"], ...]

// 30. keys: Возвращает индексы массива
let keys = breakfastList.keys();
console.log([...keys]); // [0, 1, 2, 3, 4]

// 31. values: Возвращает значения массива
let values = breakfastList.values();
console.log([...values]); // ["хлеб", "хлеб", "хлеб", "сыр", "суп"]

// 32. Array.from: Создаёт массив из других структур
let text = "молоко";
let fromText = Array.from(text);
console.log(fromText); // ["м", "о", "л", "о", "к", "о"]

// 33. Array.isArray: Проверяет, является ли значение массивом
console.log(Array.isArray(breakfastList)); // true

